on 4.0-20000127-CURRENT i386:
   when doing while(1) { if( !fork() { mmap(); exit() } }, after certain
  number of iteraions (probably ~10000), fork() ends up with kernel panic.

How-To-Repeat: 
file x.c

#include        <stdio.h>
#include        <sys/types.h>
#include	<unistd.h>
#include        <sys/stat.h>
#include        <sys/mman.h>
#include        <fcntl.h>

#define         MAX             1048576

int		fork_and_mmap( char *fname ) {
	int	pid = fork() ;

	if( pid == -1 ) {
	    perror( "fork()" ) ;
	    sleep( 1 ) ;
	} else if ( pid == 0 ) {
		int		fd ;
        	struct stat	s;
		caddr_t		this ;

                if ((fd = open(fname, O_RDONLY, 0)) < 0) {
                        perror(fname);
			exit( 1 ) ;
		}

		if (fstat(fd, &s) < 0) {
			perror("fstat") ;
			exit(0) ;
		}
		this = mmap((caddr_t) 0, s.st_size, PROT_READ,
				    MAP_PRIVATE, fd, (off_t) 0) ;
		if ((int) this == -1) {
			perror("mmap");
			sleep(1);
		}
		close( fd ) ;
		fprintf( stderr, "!" ) ;
		exit( 0 ) ;
	} else {
	    fprintf( stderr, "(" ) ;
	    /* wait(&pid) ; */
	    fprintf( stderr, ")" ) ;
	}
}

int main()
{
        int i = 0;
        int fd;
        char filename[2048];
        caddr_t this;

        while (i ++ < MAX) {
                if( gets(filename) == NULL ) {
		    fprintf( stderr, "end of file list reached\n" ) ;
		    break ;
		}
		fork_and_mmap( filename ) ;
                if (! (i % 512)) {
                        fprintf(stderr, "[%d] .. ", i);
                }

		if ( i > 200000 ) {
		    fprintf( stderr, "200000 reached, exiting\n" ) ;
		    return 0 ;
                }
        }
}

gcc -o x x.c
find / -type f -print > filelist
